123→impl std::fmt::Debug for DiscordAccountConfig {
124→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
125→        f.debug_struct("DiscordAccountConfig")
126→            .field("token", &"[REDACTED]")
127→            .field("dm_policy", &self.dm_policy)
128→            .field("group_policy", &self.group_policy)
129→            .field("mention_mode", &self.mention_mode)
130→            .field("allowlist", &self.allowlist)
131→            .field("guild_allowlist", &self.guild_allowlist)
132→            .field("model", &self.model)
133→            .field("model_provider", &self.model_provider)
134→            .field("reply_to_message", &self.reply_to_message)
135→            .field("ack_reaction", &self.ack_reaction)
136→            .field("activity", &self.activity)
137→            .field("activity_type", &self.activity_type)
138→            .field("status", &self.status)
139→            .field("otp_self_approval", &self.otp_self_approval)
140→            .field("otp_cooldown_secs", &self.otp_cooldown_secs)
141→            .field("channel_overrides", &self.channel_overrides)
142→            .field("user_overrides", &self.user_overrides)
143→            .finish()
144→    }
145→}
