147→impl ChannelConfigView for DiscordAccountConfig {
148→    fn allowlist(&self) -> &[String] {
149→        &self.allowlist
150→    }
151→
152→    fn group_allowlist(&self) -> &[String] {
153→        &self.guild_allowlist
154→    }
155→
156→    fn dm_policy(&self) -> DmPolicy {
157→        self.dm_policy.clone()
158→    }
159→
160→    fn group_policy(&self) -> GroupPolicy {
161→        self.group_policy.clone()
162→    }
163→
164→    fn model(&self) -> Option<&str> {
165→        self.model.as_deref()
166→    }
167→
168→    fn model_provider(&self) -> Option<&str> {
169→        self.model_provider.as_deref()
170→    }
171→
172→    fn channel_model(&self, channel_id: &str) -> Option<&str> {
173→        self.channel_overrides
174→            .get(channel_id)
175→            .and_then(|o| o.model.as_deref())
176→    }
177→
178→    fn channel_model_provider(&self, channel_id: &str) -> Option<&str> {
179→        self.channel_overrides
180→            .get(channel_id)
181→            .and_then(|o| o.model_provider.as_deref())
182→    }
183→
184→    fn user_model(&self, user_id: &str) -> Option<&str> {
185→        self.user_overrides
186→            .get(user_id)
187→            .and_then(|o| o.model.as_deref())
188→    }
189→
190→    fn user_model_provider(&self, user_id: &str) -> Option<&str> {
191→        self.user_overrides
192→            .get(user_id)
193→            .and_then(|o| o.model_provider.as_deref())
194→    }
195→}
