232→    #[test]
233→    fn config_round_trip() {
234→        let json = serde_json::json!({
235→            "token": "Bot MTIzNDU2.example",
236→            "dm_policy": "open",
237→            "group_policy": "allowlist",
238→            "mention_mode": "always",
239→            "allowlist": ["12345", "67890"],
240→            "guild_allowlist": ["111222333"],
241→            "model": "gpt-4o",
242→            "model_provider": "openai",
243→        });
244→        let cfg: DiscordAccountConfig =
245→            serde_json::from_value(json).unwrap_or_else(|e| panic!("parse failed: {e}"));
246→        assert_eq!(cfg.dm_policy, DmPolicy::Open);
247→        assert_eq!(cfg.group_policy, GroupPolicy::Allowlist);
248→        assert_eq!(cfg.mention_mode, MentionMode::Always);
249→        assert_eq!(cfg.allowlist, vec!["12345", "67890"]);
250→        assert_eq!(cfg.guild_allowlist, vec!["111222333"]);
251→        assert_eq!(cfg.model.as_deref(), Some("gpt-4o"));
252→
253→        // Round-trip through serde
254→        let value = serde_json::to_value(&cfg).unwrap_or_else(|e| panic!("serialize failed: {e}"));
255→        let _: DiscordAccountConfig =
256→            serde_json::from_value(value).unwrap_or_else(|e| panic!("re-parse failed: {e}"));
257→    }
