498→    #[test]
499→    fn resolve_model_user_overrides_channel() {
500→        let mut cfg = DiscordAccountConfig {
501→            model: Some("default-model".into()),
502→            ..Default::default()
503→        };
504→        cfg.channel_overrides
505→            .insert("C123".into(), ChannelOverride {
506→                model: Some("channel-model".into()),
507→                ..Default::default()
508→            });
509→        cfg.user_overrides.insert("U456".into(), UserOverride {
510→            model: Some("user-model".into()),
511→            ..Default::default()
512→        });
513→
514→        // User override wins
515→        assert_eq!(cfg.resolve_model("C123", "U456"), Some("user-model"));
516→        // Channel override wins when no user override
517→        assert_eq!(cfg.resolve_model("C123", "U999"), Some("channel-model"));
518→        // Account default when no overrides
519→        assert_eq!(cfg.resolve_model("C999", "U999"), Some("default-model"));
520→    }
