522→    #[test]
523→    fn overrides_round_trip() {
524→        let json = serde_json::json!({
525→            "token": "Bot test",
526→            "channel_overrides": {
527→                "C123": { "model": "gpt-4" }
528→            },
529→            "user_overrides": {
530→                "U456": { "model": "claude-sonnet", "model_provider": "anthropic" }
531→            }
532→        });
533→        let cfg: DiscordAccountConfig =
534→            serde_json::from_value(json).unwrap_or_else(|e| panic!("parse failed: {e}"));
535→        assert_eq!(cfg.channel_model("C123"), Some("gpt-4"));
536→        assert!(cfg.channel_model_provider("C123").is_none());
537→        assert_eq!(cfg.user_model("U456"), Some("claude-sonnet"));
538→        assert_eq!(cfg.user_model_provider("U456"), Some("anthropic"));
539→
540→        // Round-trip preserves overrides
