    /// App-level token for Socket Mode (`xapp-...`).
    /// Required when `connection_mode` is `socket_mode`.
    #[serde(serialize_with = "secret_serde::serialize_secret")]
    pub app_token: Secret<String>,

    /// How this account connects to Slack.
